<?php namespace App\Repositories\Accounting;use App\Repositories\BaseRepository;use App\Models\Accounting\JournalEntry;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class JournalEntryRepository extends BaseRepository{    public function __construct(JournalEntry $model)    {        $this->model = $model;        parent::__construct($model);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('entry_date', [$startDate, $endDate])->get();    }    public function findByAccount(int $chartOfAccountId): Collection    {        return $this->query()->whereHas('items', function ($q) use ($chartOfAccountId) {                $q->where('chart_of_account_id', $chartOfAccountId);            })->get();    }    public function findByType(string $type): Collection    {        return $this->findByField('entry_type', $type);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByReference(string $referenceType, int $referenceId): Collection    {        return $this->query()->where('reference_type', $referenceType)->where('reference_id', $referenceId)->get();    }    public function getPendingApprovals(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function approve(int $id, ?string $approvedBy = null): bool    {        $data = ['status' => 'approved', 'approved_at' => now()];        if ($approvedBy) {            $data['approved_by'] = $approvedBy;        }        return $this->update($id, $data);    }    public function searchEntries(string $keyword): Collection    {        return $this->query()->where('description', 'like', "%{$keyword}%")->orWhere('reference_number', 'like', "%{$keyword}%")->get();    }    public function getByFiscalYear(int $year): Collection    {        return $this->query()->whereYear('entry_date', $year)->get();    }    public function getDebitCreditSummary(string $startDate, string $endDate): array    {        $entries = $this->query()->whereBetween('entry_date', [$startDate, $endDate])->get();        return [            'total_debit' => $entries->sum('total_debit'),            'total_credit' => $entries->sum('total_credit'),            'count' => $entries->count(),        ];    }}